let activeEffect: Effect | null = null

interface Effect {
  fn: () => any
  deps: Set<Dep>[]
}

type Dep = Set<Effect>
type TargetMap = WeakMap<any, Map<string | symbol, Dep>>

const targetMap = new WeakMap<any, TargetMap>()

function track(target: any, key: string | symbol) {
  if (!activeEffect) return

  let depsMap = targetMap.get(target)
  if (!depsMap) {
    targetMap.set(target, (depsMap = new Map()))
  }

  let dep = depsMap.get(key)
  if (!dep) {
    depsMap.set(key, (dep = new Set()))
  }

  if (!dep.has(activeEffect)) {
    dep.add(activeEffect)
    activeEffect.deps.push(dep)
  }
}

function trigger(target: any, key: string | symbol) {
  const depsMap = targetMap.get(target)
  if (!depsMap) return

  const dep = depsMap.get(key)
  if (dep) {
    for (const effect of dep) {
      effect.fn()
    }
  }
}

function reactive<T extends object>(target: T): T {
  const handler: ProxyHandler<T> = {
    get(obj, key, receiver) {
      const result = Reflect.get(obj, key, receiver)
      track(obj, key)
      return typeof result === 'object' && result !== null ? reactive(result) : result
    },
    set(obj, key, value, receiver) {
      const oldValue = (obj as any)[key]
      const result = Reflect.set(obj, key, value, receiver)
      if (oldValue !== value) {
        trigger(obj, key)
      }
      return result
    }
  }
  return new Proxy(target, handler)
}

function effect(fn: () => void) {
  const effectFn: Effect = { fn, deps: [] }
  activeEffect = effectFn
  fn()
  activeEffect = null
  return () => {
    for (const dep of effectFn.deps) {
      dep.delete(effectFn)
    }
  }
}

