type VNode = {
  tag: string
  props: Record<string, any>
  children: (VNode | string)[]
  key?: string
}

type Element = HTMLElement

function patch(oldVNode: VNode | null, newVNode: VNode, parent: Element) {
  if (!oldVNode) {
    mount(newVNode, parent)
    return
  }

  if (typeof oldVNode === 'string' || typeof newVNode === 'string') {
    if (oldVNode !== newVNode) {
      parent.textContent = String(newVNode)
    }
    return
  }

  if (oldVNode.tag !== newVNode.tag) {
    parent.replaceChild(createElement(newVNode), oldVNode.el)
    return
  }

  updateElement(oldVNode, newVNode, parent)
  patchChildren(oldVNode, newVNode, parent)
}

function updateElement(oldVNode: VNode, newVNode: VNode, parent: Element) {
  const el = (newVNode.el = oldVNode.el || createElement(newVNode))

  // Update props
  const oldProps = oldVNode.props || {}
  const newProps = newVNode.props || {}

  for (const key in newProps) {
    if (newProps[key] !== oldProps[key]) {
      el.setAttribute(key, String(newProps[key]))
    }
  }
  for (const key in oldProps) {
    if (!(key in newProps)) {
      el.removeAttribute(key)
    }
  }
}

function patchChildren(oldVNode: VNode, newVNode: VNode, parent: Element) {
  const oldChildren = oldVNode.children || []
  const newChildren = newVNode.children || []
  const maxLen = Math.max(oldChildren.length, newChildren.length)

  for (let i = 0; i < maxLen; i++) {
    const oldChild = oldChildren[i]
    const newChild = newChildren[i]

    if (!oldChild) {
      if (typeof newChild === 'string') {
        parent.appendChild(document.createTextNode(newChild))
      } else {
        parent.appendChild(createElement(newChild))
      }
    } else if (!newChild) {
      parent.removeChild(parent.children[i])
    } else {
      patch(oldChild, newChild, parent)
    }
  }
}

function createElement(vnode: VNode): Element {
  const el = document.createElement(vnode.tag)
  vnode.el = el
  for (const [key, value] of Object.entries(vnode.props || {})) {
    el.setAttribute(key, String(value))
  }
  return el
}

function mount(vnode: VNode, parent: Element) {
  const el = createElement(vnode)
  vnode.children?.forEach(child => {
    if (typeof child === 'string') {
      el.appendChild(document.createTextNode(child))
    } else {
      mount(child, el)
    }
  })
  parent.appendChild(el)
}

import { nextTick } from 'vue'

export type SchedulerJob = () => void

enum SchedulerFlags {
  FLUSHING = 1,
  QUEUED = 2
}

const queue: SchedulerJob[] = []
const pending = new Set<SchedulerJob>()
let flushIndex = 0

const priorityQueue: Array<{ job: SchedulerJob, order: number }> = []

export function queuePostFlushJob(job: SchedulerJob) {
  if (!(job as any).__skip) {
    priorityQueue.push({ job, order: 0 })
  }
}

export function queueJob(job: SchedulerJob) {
  if (!priorityQueue.find(p => p.job === job)) {
    priorityQueue.push({ job, order: 1 })
  }
}

async function flushJobs() {
  let job
  while (priorityQueue.length > 0) {
    // Sort by priority (lower order = higher priority)
    priorityQueue.sort((a, b) => a.order - b.order)

    const { job: scheduledJob } = priorityQueue.shift()!
    await scheduledJob()
  }
}

export function nextTickWithPriority(fn?: () => void): Promise<void> {
  return nextTick().then(() => {
    if (fn) fn()
    flushJobs()
  })
}

