import { ref, watch, onUnmounted } from 'vue'

export function useDebounceSearch<T>(
  source: Ref<string>,
  fetchFn: (query: string) => Promise<T[]>,
  options: { debounceMs?: number; immediate?: boolean; minQueryLength?: number } = {}
) {
  const { debounceMs = 300, immediate = false, minQueryLength = 1 } = options
  const results = ref<T[]>([])
  const isLoading = ref(false)
  const error = ref<string | null>(null)
  let debounceTimer: ReturnType<typeof setTimeout> | null = null

  async function executeSearch(query: string) {
    if (!query.trim() || query.length < minQueryLength) {
      results.value = []
      isLoading.value = false
      return
    }

    isLoading.value = true
    error.value = null

    try {
      results.value = await fetchFn(query)
    } catch (e) {
      error.value = e instanceof Error ? e.message : 'Search failed'
    } finally {
      isLoading.value = false
    }
  }

  watch(source, (newQuery) => {
    if (debounceTimer !== null) {
      clearTimeout(debounceTimer)
    }
    debounceTimer = setTimeout(() => executeSearch(newQuery), debounceMs)
  }, { immediate })

  onUnmounted(() => {
    if (debounceTimer !== null) {
      clearTimeout(debounceTimer)
    }
  })

  return { results, isLoading, error }
}

