type FilterFn<T> = (item: T, context: FilterContext) => boolean

interface FilterContext {
  searchTerm: string
  categories: string[]
  priceRange: { min: number; max: number }
  sortBy: string
  sortOrder: 'asc' | 'desc'
}

export class FilterPipeline<T> {
  private filters: FilterFn<T>[] = []
  private context: FilterContext

  constructor(context: FilterContext) {
    this.context = context
  }

  addFilter(filter: FilterFn<T>): FilterPipeline<T> {
    this.filters.push(filter)
    return this
  }

  execute(items: T[]): T[] {
    let result = [...items]

    // Apply text search filter
    if (this.context.searchTerm) {
      result = result.filter(item =>
        JSON.stringify(item).toLowerCase().includes(this.context.searchTerm.toLowerCase())
      )
    }

    // Apply category filter
    if (this.context.categories.length > 0) {
      result = result.filter(item => {
        const categories = (item as any).categories || []
        return this.context.categories.some(cat => categories.includes(cat))
      })
    }

    // Apply price range filter
    result = result.filter(item => {
      const price = (item as any).price ?? 0
      return price >= this.context.priceRange.min && price <= this.context.priceRange.max
    })

    // Apply custom filters
    for (const filter of this.filters) {
      result = result.filter(item => filter(item, this.context))
    }

    // Sort
    result.sort((a, b) => {
      const aVal = (a as any)[this.context.sortBy] ?? 0
      const bVal = (b as any)[this.context.sortBy] ?? 0
      return this.context.sortOrder === 'desc' ? bVal - aVal : aVal - bVal
    })

    return result
  }
}

